    def __init__(self):
        self.part1 = []
        for l, r in product(range(2**9), range(2**7)):
            l = self.misty_s9[l]
            l ^= r  # zero-extend 7->9

            l, r = r, l

            l = self.misty_s7[l]
            l ^= r & 127  # truncate 9->7

            y = (l << 9) | r
            self.part1.append(y)
        assert sorted(self.part1) == sorted(range(2**16))

        self.part2 = []
        for l, r in product(range(2**7), range(2**9)):
            l, r = r, l

            l = self.misty_s9[l]
            l ^= r  # zero-extend 7->9

            l, r = r, l
            y = (l << 9) | r
            self.part2.append(y)
        assert sorted(self.part2) == sorted(range(2**16))

    def get_keys(self):
        return list(range(2**16))

    def get_part1(self):
        return self.part1

    def get_part2(self):
        return self.part2

    def get_full(self, key):
        res = []
        for x in range(2**16):
            x = self.part1[x]
            x = x ^ key
            x = self.part2[x]
            res.append(x)
        return res
